      "python_code": "def shortest_path(graph: dict[str, list[str]], start: str, goal: str) -> list[str]:
    queue = [[start]]
    seen = {start}

    while queue:
        path = queue.pop(0)
        current = path[-1]

        if current == goal:
            return path

        for next_node in graph[current]:
            if next_node not in seen:
                seen.add(next_node)
                queue.append(path + [next_node])

    return []

